      action: "record",
      tool: "meta",
      parameters: { self: true },
      output: "Witness observing itself",
      insight: "The fifth mode is reflexive",
    });

    expect(result).toContain("Witnessed meta");
    expect(result).toContain("Total observations: 1");
  });
});
